int id_check(char id[SIZ_ID]) {
  int aux, cpf[CPF_MIN], cnpj[CNPJ_MIN], confirmation, aux2, idAux[SIZ_ID];
  int tamanhoString = strlen(id);
  confirmation = TRUE;
  if (tamanhoString == CPF_MIN || (tamanhoString == CPF_MAX && !(id[3] >= NUMERO_MIN && id[3] <= NUMERO_MAX))) {
    if (tamanhoString == CPF_MIN) {
      for (aux = 0; aux < CPF_MIN; aux++) {
        cpf[aux] = id[aux] - NUMERO_MIN;
      }
    }

    if (cpf[1] == cpf[0] && cpf[2] == cpf[1] && cpf[3] == cpf[2] &&
        cpf[4] == cpf[3] && cpf[5] == cpf[4] && cpf[6] == cpf[5] &&
        cpf[7] == cpf[6] && cpf[8] == cpf[7] && cpf[9] == cpf[8] &&
        cpf[10] == cpf[9]) {
      confirmation = FALSE;
    }
    if (confirmation == TRUE) { //First digit verification
      for (aux = 0; aux < CPF_MIN; aux++) {
        idAux[aux] = cpf[aux];
      }
      aux2 = 10;
      for (aux = 0; aux < (CPF_MIN - 2); aux++) {
        idAux[aux] *= aux2;
        aux2--;
      }
      aux2 = 0;
      for (aux = 0; aux < (CPF_MIN - 2); aux++) {
        aux2 += idAux[aux];
      }
      aux2 *= 10;
      aux2 %= 11;
      if (aux2 != cpf[9] && !(aux2 == 10 || aux2 == 11)) {
        confirmation = FALSE;
      }
      if ((aux2 == 10 || aux2 == 11) && cpf[9] != 0) {
        confirmation = FALSE;
      }
    }
    if (confirmation == TRUE) { //Second digit verification
      for (aux = 0; aux < CPF_MIN; aux++) {
        idAux[aux] = cpf[aux];
      }
      aux2 = 11;
      for (aux = 0; aux < (CPF_MIN - 1); aux++) {
        idAux[aux] *= aux2;
        aux2--;
      }
      aux2 = 0;
      for (aux = 0; aux < (CPF_MIN - 1); aux++) {
        aux2 += idAux[aux];
      }
      aux2 *= 10;
      aux2 %= 11;
      if (aux2 != cpf[10] && !(aux2 == 10 || aux2 == 11)) {
        confirmation = FALSE;
      }
      if ((aux2 == 10 || aux2 == 11) && cpf[10] != 0) {
        confirmation = FALSE;
      }
    }
  } else {
    if (tamanhoString == CNPJ_MIN || (tamanhoString == CNPJ_MAX && (id[3] >= NUMERO_MIN && id[3] <= NUMERO_MAX))) {
      if (tamanhoString == CNPJ_MIN) {
        for (aux = 0; aux < CNPJ_MIN; aux++) {
          cnpj[aux] = id[aux] - NUMERO_MIN;
        }
      }

      idAux[0] = cnpj[0] * 5;
      idAux[1] = cnpj[1] * 4;
      idAux[2] = cnpj[2] * 3;
      idAux[3] = cnpj[3] * 2;
      idAux[4] = cnpj[4] * 9;
      idAux[5] = cnpj[5] * 8;
      idAux[6] = cnpj[6] * 7;
      idAux[7] = cnpj[7] * 6;
      idAux[8] = cnpj[8] * 5;
      idAux[9] = cnpj[9] * 4;
      idAux[10] = cnpj[10] * 3;
      idAux[11] = cnpj[11] * 2;
      aux2 = 0;
      for (aux = 0; aux < (CNPJ_MIN - 2); aux++) {
        aux2 += idAux[aux];
      }
      aux2 %= 11;
      if (!(aux2 < 2 && cnpj[12] == 0)) {
        aux2 = 11 - aux2;
        if (aux2 != cnpj[12]) {
          confirmation = FALSE;
        }
      } //organizing cnpj
      idAux[0] = cnpj[0] * 6; 
      idAux[1] = cnpj[1] * 5;
      idAux[2] = cnpj[2] * 4;
      idAux[3] = cnpj[3] * 3;
      idAux[4] = cnpj[4] * 2;
      idAux[5] = cnpj[5] * 9;
      idAux[6] = cnpj[6] * 8;
      idAux[7] = cnpj[7] * 7;
      idAux[8] = cnpj[8] * 6;
      idAux[9] = cnpj[9] * 5;
      idAux[10] = cnpj[10] * 4;
      idAux[11] = cnpj[11] * 3;
      idAux[12] = cnpj[12] * 2;
      aux2 = 0;
      for (aux = 0; aux < (CNPJ_MIN - 1); aux++) {
        aux2 += idAux[aux];
      }
      aux2 %= 11;
      if (!(aux2 < 2 && cnpj[13] == 0)) {
        aux2 = 11 - aux2;
        if (aux2 != cnpj[13]) {
          confirmation = FALSE;
        }
      }
    } else {
      confirmation = FALSE;
    }
  }
  return confirmation;
}
int date_check(char data[SIZ_DATE]) { //Get date in int type.
  int day, month, year, aux, bissexto;
  int confirmation = 1;
  aux = strlen(data);
  if (aux == DATE_MIN || aux == DATE_MAX) {
    if (aux == DATE_MIN) {
      day = (data[0] - NUMERO_MIN) * 10;
      day += (data[1] - NUMERO_MIN);
      month = (data[2] - NUMERO_MIN) * 10;
      month += (data[3] - NUMERO_MIN);
      year = (data[4] - NUMERO_MIN) * 1000;
      year += (data[5] - NUMERO_MIN) * 100;
      year += (data[6] - NUMERO_MIN) * 10;
      year += (data[7] - NUMERO_MIN);
    }
    if (aux == DATE_MAX) {
      day = (data[0] - NUMERO_MIN) * 10;
      day += (data[1] - NUMERO_MIN);
      month = (data[3] - NUMERO_MIN) * 10;
      month += (data[4] - NUMERO_MIN);
      year = (data[6] - NUMERO_MIN) * 1000;
      year += (data[7] - NUMERO_MIN) * 100;
      year += (data[8] - NUMERO_MIN) * 10;
      year += (data[9] - NUMERO_MIN);
    }
    if (month > 12 || month < 1) {
      confirmation = FALSE;
      return confirmation;
    } else {
      if(day >29 && month == 1){
        confirmation = FALSE;
        return confirmation;
      }
      if (day == 31) {
        switch (month) {
          case 1: // january
            confirmation = TRUE;
            return confirmation;
            break;
          case 3: // march
            confirmation = TRUE;
            return confirmation;
            break;
          case 5: // may
            confirmation = TRUE;
            return confirmation;
            break;
          case 7: // july
            confirmation = TRUE;
            return confirmation;
            break;
          case 8: // august
            confirmation = TRUE;
            return confirmation;
            break;
          case 10: // october
            confirmation = TRUE;
            return confirmation;
            break;
          case 12: // december
            confirmation = TRUE;
            return confirmation;
            break;
          default:
            confirmation = FALSE;
            return confirmation;
            break;
        }
      }
      if (day > 31 || day < 1) {
        confirmation = FALSE;
        return confirmation;
      } 
    }
  } else {
    confirmation = FALSE;
  }
  return confirmation;
}
